fp1 = ""

fp2 = ""

fp3 = ""

p1, p2, p3 = int(fp1, 2), int(fp2, 2), int(fp3, 2)

result = (p1 & p2) & ~p3

# Count how many such bits exist
count = result.bit_count()

# Get positions
positions = [i for i in range(result.bit_length()) if (result >> i) & 1]

print("Count:", count)
print("Positions:", positions)